INSERT INTO ws_view_history (user_id, document_id, viewed_at, client_ip)
SELECT u.user_id, d.document_id,
       date_trunc('week', CURRENT_DATE) - interval '1 week'
         + make_interval(days => 1, hours => 0),
       '172.20.0.2'::inet
FROM ws_user u
JOIN (SELECT document_id FROM ws_document ORDER BY document_id
      OFFSET 0 LIMIT 1) d ON TRUE
WHERE u.login = 'td_7_0079_plpx7b';

