         + make_interval(days => 5, hours => 6),
       '172.20.14.6'::inet
FROM ws_user u
JOIN (SELECT document_id FROM ws_document ORDER BY document_id
      OFFSET 2 LIMIT 1) d ON TRUE
WHERE u.login = 'mod1';

